Here's a modern MSTest approach for testing `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    [Timeout(5000)] // MSTest v3+ per-test timeout in ms
    public async Task FetchAsync_ReturnsContent_WhenSuccessful()
    {
        var handler = new MockHttpMessageHandler("expected content", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("expected content", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenStatusCodeIsError()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExceptionAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var handler = new MockHttpMessageHandler("content", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExceptionAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PropagatesCancellationToken()
    {
        using var cts = new CancellationTokenSource();
        var handler = new CapturingHttpMessageHandler(HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await fetcher.FetchAsync("https://example.com", cts.Token);

        Assert.AreEqual(cts.Token, handler.CapturedToken);
    }

    // Lightweight mock handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode, TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }

    private sealed class CapturingHttpMessageHandler : HttpMessageHandler
    {
        private readonly HttpStatusCode _statusCode;
        public CancellationToken CapturedToken { get; private set; }

        public CapturingHttpMessageHandler(HttpStatusCode statusCode) => _statusCode = statusCode;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            CapturedToken = cancellationToken;
            return Task.FromResult(new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent("")
            });
        }
    }
}
```

**Key modern MSTest patterns used:**

| Pattern | Detail |
|---------|--------|
| `async Task` return | MSTest natively awaits test methods — no `GetAwaiter().GetResult()` needed |
| `[Timeout(ms)]` | Per-test timeout; catches hangs without blocking the entire run |
| `ThrowsExceptionAsync<T>` | Proper async exception assertion (not `ThrowsException`) |
| `CancellationTokenSource` | Verifies the token propagates and cancellation is respected |
| Custom `HttpMessageHandler` | Avoids mocking `HttpClient` directly (which is not designed for mocking) |

> **MSTest v3+ note:** If using MSTest 3.x with `[Timeout]`, the framework cooperatively cancels via `TestContext.CancellationTokenSource`. For MSTest v4, prefer `Assert.ThrowsExactly` over `ThrowsException` for stricter type matching.
